@pytest.mark.parametrize(
    "spec, method, path, has_declared_response, idempotent, auth_policy, "
    "rate_limit_bucket, request_model, params",
    ENDPOINT_CASES,
)
def test_generated_endpoint_spec_matches_catalog(
    spec: EndpointSpec[ResponseModel],
    method: str,
    path: str,
    has_declared_response: bool,
    idempotent: bool,
    auth_policy: str,
    rate_limit_bucket: str,
    request_model: str | None,
    params: tuple[tuple[str, str, str], ...],
) -> None:
    assert spec.method == method
    assert spec.path == path
    assert spec.idempotent is idempotent
    assert spec.auth_policy.name == auth_policy
    assert spec.rate_limit_bucket == rate_limit_bucket
    if request_model is None:
        assert spec.request_model is None
    else:
        assert spec.request_model is not None
        assert spec.request_model.__name__ == request_model
    param_fields = tuple((param.name, param.location, param.python_name) for param in spec.params)
    assert param_fields == params
    if has_declared_response:
        assert spec.response_model is not ResponseModel
